# Rate limiting: simple in-memory tracker
from collections import defaultdict
import time

rate_limit_store = defaultdict(list)
RATE_LIMIT_MAX_REQUESTS = int(os.environ.get("RATE_LIMIT_MAX", 60))
RATE_LIMIT_WINDOW_SECONDS = int(os.environ.get("RATE_LIMIT_WINDOW", 60))


def check_rate_limit(client_ip):
    now = time.time()
    window_start = now - RATE_LIMIT_WINDOW_SECONDS
    # Clean old entries
    rate_limit_store[client_ip] = [
        t for t in rate_limit_store[client_ip] if t > window_start
    ]
    if len(rate_limit_store[client_ip]) >= RATE_LIMIT_MAX_REQUESTS:
        return False
    rate_limit_store[client_ip].append(now)
    return True


def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get("X-API-Key", "")
        if not api_key or api_key != ADMIN_API_KEY:
            app.logger.warning(
                "Unauthorized access attempt from %s", request.remote_addr
            )
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated_function


def validate_command(command_str):
    """Parse and validate the Redis command string."""
    if not command_str or not isinstance(command_str, str):
        return None, "Command must be a non-empty string"

    command_str = command_str.strip()
    if not command_str:
        return None, "Command must be a non-empty string"

    # Limit command length to prevent abuse
    if len(command_str) > 4096:
        return None, "Command too long (max 4096 characters)"

    # Reject any null bytes or control characters (except spaces/tabs)
    if re.search(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]', command_str):
        return None, "Command contains invalid characters"

    try:
        parts = shlex.split(command_str)
    except ValueError as e:
        return None, f"Invalid command syntax: {e}"

    if not parts:
        return None, "Empty command after parsing"

    cmd_name = parts[0].upper()

    if cmd_name in BLOCKED_COMMANDS:
        app.logger.warning(
            "Blocked dangerous command attempt: %s from %s",
            cmd_name,
            request.remote_addr,
        )
        return None, f"Command '{cmd_name}' is not allowed"

    if cmd_name not in ALLOWED_COMMANDS:
        return None, (
            f"Command '{cmd_name}' is not in the allowed commands list. "
            f"Allowed commands: {', '.join(sorted(ALLOWED_COMMANDS))}"
        )

    # Special validation for KEYS command to prevent expensive patterns
    if cmd_name == "KEYS":
        if len(parts) < 2:
            return None, "KEYS command requires a pattern argument"
        pattern = parts[1]
        # Block overly broad patterns in production
        if pattern == "*":
            app.logger.warning(
                "KEYS * attempted from %s - consider using SCAN instead",
                request.remote_addr,
            )
            # Allow but log warning; in stricter environments, you could block this

    return parts, None


def serialize_result(result):
    """Safely serialize Redis result for JSON response."""
    if result is None:
        return None
    if isinstance(result, bytes):
        try:
            return result.decode("utf-8")
        except UnicodeDecodeError:
            return result.hex()
    if isinstance(result, (list, tuple)):
        return [serialize_result(item) for item in result]
    if isinstance(result, dict):
        return {
            serialize_result(k): serialize_result(v) for k, v in result.items()
        }
    if isinstance(result, (int, float, str, bool)):
        return result
    return str(result)


@app.route("/api/admin/redis", methods=["POST"])
@require_api_key
def execute_redis_command():
    """Execute a validated Redis command for cache management."""
    client_ip = request.remote_addr

    if not check_rate_limit(client_ip):
        return jsonify({"error": "Rate limit exceeded. Try again later."}), 429

    # Accept command from JSON body (more secure than query params for POST)
    data = request.get_json(silent=True)
    if data and "command" in data:
        command_str = data["command"]
    else:
        command_str = request.args.get("command", "")

    parts, error = validate_command(command_str)
    if error:
        return jsonify({"error": error}), 400

    cmd_name = parts[0].upper()
    cmd_args = parts[1:]

    app.logger.info(
        "Executing Redis command: %s with %d args from %s",
        cmd_name,
        len(cmd_args),
        client_ip,
    )

    try:
        result = redis_client.execute_command(cmd_name, *cmd_args)
        serialized = serialize_result(result)
        return jsonify({
            "success": True,
            "command": cmd_name,
            "result": serialized,
        }), 200
    except redis.RedisError as e:
        app.logger.error("Redis error executing '%s': %s", cmd_name, str(e))
        return jsonify({
            "success": False,
            "error": f"Redis error: {str(e)}",
        }), 500
    except Exception as e:
        app.logger.error(
            "Unexpected error executing '%s': %s", cmd_name, str(e)
        )
        return jsonify({
            "success": False,
            "error": "An unexpected error occurred",
        }), 500


