def redis_health():
    """Check Redis connection health."""
    try:
        redis_client.ping()
        return jsonify({"status": "healthy", "connected": True}), 200
    except redis.RedisError as e:
        return jsonify({
            "status": "unhealthy",
            "connected": False,
            "error": str(e),
        }), 503


